/**
 * Unit tests for lifecycle/mcp-health-check hook.
 *
 * Focus: the tavily check must NOT warn when the API key is supplied at launch
 * (env block, inline KEY=..., or a secret-manager fetch like `op read`) rather
 * than via process.env. The dispatcher test mocks this hook, so this is the
 * only coverage of the real checkServer logic.
 */

import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import { mkdtempSync, rmSync, writeFileSync } from 'node:fs';
import { join } from 'node:path';
import { tmpdir } from 'node:os';
import { mcpHealthCheck } from '../../lifecycle/mcp-health-check.js';
import type { HookInput } from '../../types.js';

let projectDir: string;
const savedTavilyKey = process.env.TAVILY_API_KEY;
const savedSkip = process.env.ORCHESTKIT_SKIP_SLOW_HOOKS;

function writeMcpConfig(servers: Record<string, unknown>): void {
  writeFileSync(join(projectDir, '.mcp.json'), JSON.stringify({ mcpServers: servers }));
}

function run(): ReturnType<typeof mcpHealthCheck> {
  return mcpHealthCheck({ project_dir: projectDir } as unknown as HookInput);
}

/** The misconfiguration message (if any) the hook surfaced to the user. */
function warning(result: ReturnType<typeof mcpHealthCheck>): string {
  return result.hookSpecificOutput?.additionalContext ?? '';
}

beforeEach(() => {
  projectDir = mkdtempSync(join(tmpdir(), 'mcp-health-'));
  delete process.env.TAVILY_API_KEY;
  delete process.env.ORCHESTKIT_SKIP_SLOW_HOOKS;
});

afterEach(() => {
  rmSync(projectDir, { recursive: true, force: true });
  if (savedTavilyKey === undefined) delete process.env.TAVILY_API_KEY;
  else process.env.TAVILY_API_KEY = savedTavilyKey;
  if (savedSkip === undefined) delete process.env.ORCHESTKIT_SKIP_SLOW_HOOKS;
  else process.env.ORCHESTKIT_SKIP_SLOW_HOOKS = savedSkip;
});

describe('mcp-health-check: tavily key sourcing', () => {
  it('does NOT warn when the key is fetched via 1Password op read (real-world config)', () => {
    writeMcpConfig({
      tavily: {
        command: 'sh',
        args: ['-c', "TAVILY_API_KEY=$(op read 'op://Platform/Tavily-API-Key/credential') exec npx -y tavily-mcp@0.2.20"],
      },
    });
    expect(warning(run())).toBe('');
  });

  it('does NOT warn when the key is declared in the server env block', () => {
    writeMcpConfig({
      tavily: { command: 'npx', args: ['-y', 'tavily-mcp'], env: { TAVILY_API_KEY: 'placeholder-value' } },
    });
    expect(warning(run())).toBe('');
  });

  it('does NOT warn when the key is inlined in the launch command', () => {
    writeMcpConfig({
      tavily: { command: 'sh', args: ['-c', 'TAVILY_API_KEY=placeholder-value exec npx -y tavily-mcp'] },
    });
    expect(warning(run())).toBe('');
  });

  it('does NOT warn when TAVILY_API_KEY is present in the process env', () => {
    process.env.TAVILY_API_KEY = 'placeholder-value';
    writeMcpConfig({ tavily: { command: 'npx', args: ['-y', 'tavily-mcp'] } });
    expect(warning(run())).toBe('');
  });

  it('WARNS when the key is genuinely missing (no env, no injection)', () => {
    writeMcpConfig({ tavily: { command: 'npx', args: ['-y', 'tavily-mcp'] } });
    expect(warning(run())).toContain('tavily is enabled but TAVILY_API_KEY');
  });

  it('does NOT warn when tavily is explicitly disabled', () => {
    writeMcpConfig({ tavily: { command: 'npx', args: ['-y', 'tavily-mcp'], disabled: true } });
    expect(warning(run())).toBe('');
  });
});
